  uint32_t outC = static_cast<uint32_t>(*attrs->GetAttrPointer<int64_t>(1));
  uint32_t kernelH = static_cast<uint32_t>(*attrs->GetAttrPointer<int64_t>(2));
  uint32_t kernelW = static_cast<uint32_t>(*attrs->GetAttrPointer<int64_t>(3));
