  int32_t dilationW = static_cast<int32_t>(*attrs->GetAttrPointer<int64_t>(9));

  // output size after conv2d
  int32_t outH_conv = (H + 2 * padH - dilationH * (static_cast<int32_t>(kernelH) - 1) - 1) / strideH + 1;
  int32_t outW_conv = (W + 2 * padW - dilationW * (static_cast<int32_t>(kernelW) - 1) - 1) / strideW + 1;
  // avgpool2d with same kernel, stride, pad (kernel size equals conv kernel)
  uint32_t outH = (static_cast<uint32_t>(outH_conv) + 2 * static_cast<uint32_t>(padH) - kernelH) / static_cast<uint32_t>(strideH) + 1;
  uint32_t outW = (static_cast<uint32_t>(outW_conv) + 2 * static_cast<uint32_t>(padW) - kernelW) / static_cast<uint32_t>(strideW) + 1;

  // simple tiling
  uint32_t tileLen = 256 * 1024;
  if (tileLen > totalLength) tileLen = totalLength;
  uint32_t blockDim = 8;

  context->SetBlockDim(blockDim);

  tiling.set_totalLength(totalLength);
  tiling.set_tileLength(tileLen);
  tiling.set_blockDim(blockDim);
  tiling.set_N(N);
  tiling.set_C(C);
  tiling.set_H(H);
  tiling.set_W(W);
